/* ============================================================
   Bishop — glyph-dither 3D render (Unicorn Studio recreation)
   Transparent background, no UI. Drop-in for Webflow.

   USAGE (Webflow Embed element or before </body>):
     <div id="bishop-dots" style="width:100%;aspect-ratio:287/398;"></div>
     <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
     <script src="bishop-dots.js"></script>

   The canvas fills the #bishop-dots container and stays transparent,
   so whatever is behind the div in Webflow shows through.
   ============================================================ */
(function () {
  'use strict';

  /* ---------------- SETTINGS (edit these) ---------------- */
  var SETTINGS = {
    container: '#bishop-dots',  // CSS selector of the wrapper div
    color:     '#076e69',       // model tint  (your pick: rgb(7,110,105))
    dotPitchDesktop: 5,         // dot cell size (px) at desktop widths (>= 1200px viewport)
    dotPitchMobile:  3,         // dot cell size (px) on small phones (<= 480px viewport)
    //                          -> in between, the size scales smoothly with the device
    dotSize:   0.45,            // 0..1 -> smallest..largest dot (same size everywhere)
    spin:      true,            // slow auto-rotation
    spinSpeed: 0.45,            // radians/sec
    drag:      true             // drag to rotate
  };
  /* -------------------------------------------------------- */

  var GEO_POS = '';
  var GEO_NOR = '';
  var GEO_IDX = '';
  var SPRITE_B64 = ''; // the original Unicorn Studio porthole.png (10 glyphs)

  function b64ToBuf(b64) {
    var s = atob(b64), u = new Uint8Array(s.length);
    for (var i = 0; i < s.length; i++) u[i] = s.charCodeAt(i);
    return u.buffer;
  }

  function init() {
    var stage = document.querySelector(SETTINGS.container);
    if (!stage || !window.THREE) return;

    var positions = new Float32Array(b64ToBuf(GEO_POS));
    var normals   = new Float32Array(b64ToBuf(GEO_NOR));
    var indices   = new Uint16Array(b64ToBuf(GEO_IDX));

    /* renderer — fully transparent */
    var renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setClearColor(0x000000, 0);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.domElement.style.display = 'block';
    renderer.domElement.style.width = '100%';
    renderer.domElement.style.height = '100%';
    stage.appendChild(renderer.domElement);

    /* scene */
    var scene = new THREE.Scene();
    var camera = new THREE.PerspectiveCamera(32, 1, 0.1, 50);
    camera.position.set(0, 0, 4.6); // distance is re-fitted in resize()
    camera.lookAt(0, 0, 0);

    /* light rig derived from one tint (original "APTA - Bishop" structure) */
    var c    = new THREE.Color(SETTINGS.color);
    var dark = c.clone().multiplyScalar(0.5);
    var lift = c.clone().lerp(new THREE.Color(0xffffff), 0.4);
    var keyc = c.clone().lerp(new THREE.Color(0xffffff), 0.8);

    scene.add(new THREE.AmbientLight(c, 0.55));
    var key = new THREE.DirectionalLight(keyc, 0.9);
    key.position.set(2.2, 3.0, 3.0); scene.add(key);
    var fill = new THREE.DirectionalLight(dark, 1.4);
    fill.position.set(-2.5, -0.8, -2.0); scene.add(fill);
    var rim = new THREE.DirectionalLight(lift, 0.5);
    rim.position.set(0, 2.5, -3.5); scene.add(rim);

    /* bishop mesh (original GLB geometry, baked in) */
    var geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geo.setAttribute('normal',   new THREE.BufferAttribute(normals, 3));
    geo.setIndex(new THREE.BufferAttribute(indices, 1));
    var mat = new THREE.MeshStandardMaterial({ color: 0xf2fffd, metalness: 0.3, roughness: 0.55 });
    var pivot = new THREE.Group();
    pivot.add(new THREE.Mesh(geo, mat));
    scene.add(pivot);


    /* glyph sprite (the exact porthole.png from the original scene) */
    var sprite = new THREE.TextureLoader().load('data:image/png;base64,' + SPRITE_B64);
    sprite.minFilter = THREE.LinearFilter;
    sprite.magFilter = THREE.LinearFilter;
    sprite.wrapS = sprite.wrapT = THREE.ClampToEdgeWrapping;
    sprite.generateMipmaps = false;

    /* dot-dither post pass — port of the original glyphDither shader,
       with ONE fixed glyph so every dot is the same size */
    var rt = new THREE.WebGLRenderTarget(2, 2, {
      minFilter: THREE.LinearFilter, magFilter: THREE.LinearFilter, format: THREE.RGBAFormat
    });
    var postScene = new THREE.Scene();
    var postCam = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
    var uniforms = {
      uScene:      { value: rt.texture },
      uSprite:     { value: sprite },
      uResolution: { value: new THREE.Vector2(2, 2) },
      uGrid:       { value: 140 },            // recomputed from dotPitch in resize()
      uGain:       { value: SETTINGS.dotSize },
      uGlyphCount: { value: 10.0 },
      uGlyphPx:    { value: 40.0 }
    };
    var postMat = new THREE.ShaderMaterial({
      uniforms: uniforms,
      transparent: true,
      vertexShader: [
        'varying vec2 vUv;',
        'void main(){ vUv = uv; gl_Position = vec4(position.xy, 0.0, 1.0); }'
      ].join('\n'),
      fragmentShader: [
        'precision highp float;',
        'varying vec2 vUv;',
        'uniform sampler2D uScene;',
        'uniform sampler2D uSprite;',
        'uniform vec2  uResolution;',
        'uniform float uGrid;',
        'uniform float uGain;',
        'uniform float uGlyphCount;',
        'uniform float uGlyphPx;',
        'float luma(vec3 c){ return dot(c, vec3(0.2126, 0.7152, 0.0722)); }',
        'void main(){',
        '  float aspectRatio = uResolution.x / uResolution.y;',
        '  /* square cells in PIXELS, so dots stay circular at any container ratio */',
        '  vec2 cellSize = vec2(1.0 / (uGrid * aspectRatio), 1.0 / uGrid);',
        '  vec2 pos = vec2(0.5);',
        '  vec2 cell = floor((vUv - pos) / cellSize);',
        '  vec2 pixelatedCoord = (cell + 0.5) * cellSize + pos;',
        '  vec4 color = texture2D(uScene, pixelatedCoord);',
        '  vec4 here  = texture2D(uScene, vUv);',
        '  if (here.a < 0.01) discard;',
        '  vec4 src = color.a > 0.5 ? color : here;  // cell color, per-pixel at the rim',
        '  vec3 scn = src.rgb / max(src.a, 1e-4);',
        '  float luminance = luma(scn);',
        '  float glyphSelection  = clamp(floor(luminance * uGlyphCount), 0.0, uGlyphCount - 1.0);',
        '  float phasedSelection = clamp(floor(uGain * (uGlyphCount - 1.0) + 0.5), 0.0, uGlyphCount - 1.0);',
        '  vec2 localOffset = mod(vUv - pos, cellSize) / cellSize;',
        '  float inset = 0.5 / uGlyphPx;',
        '  localOffset = clamp(localOffset, inset, 1.0 - inset);',
        '  vec2 spriteUv = vec2((phasedSelection + localOffset.x) / uGlyphCount, localOffset.y);',
        '  float galpha = smoothstep(0.0, 1.0, texture2D(uSprite, spriteUv).r);',
        '  vec3 cc = (scn - glyphSelection * 0.04) * 1.4;',
        '  vec3 result = mix(vec3(0.0), cc, galpha);',
        '  gl_FragColor = vec4(result, here.a);  // smooth edge alpha',
        '}'
      ].join('\n')
    });
    postScene.add(new THREE.Mesh(new THREE.PlaneBufferGeometry(2, 2), postMat));

    /* size to the container + fit the model edge-to-edge */
    function resize() {
      var w = stage.clientWidth || 1, h = stage.clientHeight || 1;
      renderer.setSize(w, h, false);
      camera.aspect = w / h;

      /* device-responsive dot size: pitch (px per dot) eases from
         dotPitchMobile at <=480px viewports to dotPitchDesktop at >=1200px,
         then rows = height / pitch */
      var vw = window.innerWidth || w;
      var t = Math.min(1, Math.max(0, (vw - 480) / (1200 - 480)));
      var pitch = SETTINGS.dotPitchMobile + (SETTINGS.dotPitchDesktop - SETTINGS.dotPitchMobile) * t;
      uniforms.uGrid.value = Math.max(20, h / pitch);

      /* tightest camera distance with NO clipping at any Y-rotation:
         for each vertex (radius r, height y) the worst angles give
           vertical:   D >= r + |y| / tan(fov/2)
           horizontal: D >= r * sqrt(1 + k*k), k = 1 / (tan * aspect)
         take the max over all vertices -> model spans edge to edge */
      var tanH = Math.tan(camera.fov * Math.PI / 360);
      var k = 1 / (tanH * camera.aspect);
      var D = 0;
      for (var vi = 0; vi < positions.length; vi += 3) {
        var x = positions[vi], y = Math.abs(positions[vi + 1]), z = positions[vi + 2];
        var r = Math.sqrt(x * x + z * z);
        var dv = Math.max(r + y / tanH, r * Math.sqrt(1 + k * k));
        if (dv > D) D = dv;
      }
      camera.position.set(0, 0, D * 1.005);   // 0.5% safety, model fills the frame
      camera.lookAt(0, 0, 0);
      camera.updateProjectionMatrix();

      var dw = renderer.domElement.width, dh = renderer.domElement.height;
      /* supersample the offscreen pass (render targets get no MSAA) so the
         model silhouette comes out smooth; capped for GPU safety */
      var ss = Math.max(1, Math.min(2, 4096 / Math.max(dw, dh)));
      rt.setSize(Math.round(dw * ss), Math.round(dh * ss));
      uniforms.uResolution.value.set(dw, dh);
    }
    if (window.ResizeObserver) new ResizeObserver(resize).observe(stage);
    window.addEventListener('resize', resize);
    resize();

    /* drag to rotate */
    var spinning = SETTINGS.spin && !window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    var dragging = false, lastX = 0, lastY = 0, velX = 0;
    var rotY = 0.6, rotX = 0;
    if (SETTINGS.drag) {
      stage.style.cursor = 'grab';
      stage.style.touchAction = 'pan-y';
      stage.addEventListener('pointerdown', function (e) {
        dragging = true; lastX = e.clientX; lastY = e.clientY;
        stage.style.cursor = 'grabbing';
        stage.setPointerCapture(e.pointerId);
      });
      stage.addEventListener('pointermove', function (e) {
        if (!dragging) return;
        var dx = e.clientX - lastX, dy = e.clientY - lastY;
        lastX = e.clientX; lastY = e.clientY;
        rotY += dx * 0.008;
        rotX = Math.max(-0.3, Math.min(0.3, rotX + dy * 0.005));
        velX = dx * 0.008;
      });
      var endDrag = function () { dragging = false; stage.style.cursor = 'grab'; };
      stage.addEventListener('pointerup', endDrag);
      stage.addEventListener('pointercancel', endDrag);
    }

    /* render loop */
    var prev = performance.now();
    function tick(now) {
      var dt = Math.min((now - prev) / 1000, 0.05);
      prev = now;
      if (!dragging) {
        if (spinning) rotY += dt * SETTINGS.spinSpeed;
        rotY += velX; velX *= 0.94;
        rotX *= 0.97;
      }
      pivot.rotation.set(rotX, rotY, 0);

      renderer.setRenderTarget(rt);
      renderer.setClearColor(0x000000, 0);
      renderer.clear();
      renderer.render(scene, camera);

      renderer.setRenderTarget(null);
      renderer.clear();
      renderer.render(postScene, postCam);

      requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
